309	    #[allow(clippy::too_many_arguments)]
310	    fn run_commands(
311	        event: HookEvent,
312	        commands: &[String],
313	        tool_name: &str,
314	        tool_input: &str,
315	        tool_output: Option<&str>,
316	        is_error: bool,
317	        abort_signal: Option<&HookAbortSignal>,
318	        mut reporter: Option<&mut dyn HookProgressReporter>,
319	    ) -> HookRunResult {
320	        if commands.is_empty() {
321	            return HookRunResult::allow(Vec::new());
322	        }
323	
324	        if abort_signal.is_some_and(HookAbortSignal::is_aborted) {
325	            return HookRunResult {
326	                denied: false,
327	                failed: false,
328	                cancelled: true,
329	                messages: vec![format!(
330	                    "{} hook cancelled before execution",
331	                    event.as_str()
332	                )],
333	                permission_override: None,
334	                permission_reason: None,
335	                updated_input: None,
336	            };
337	        }
338	
339	        let payload = hook_payload(event, tool_name, tool_input, tool_output, is_error).to_string();
340	        let mut result = HookRunResult::allow(Vec::new());
341	
342	        for command in commands {
343	            if let Some(reporter) = reporter.as_deref_mut() {
344	                reporter.on_event(&HookProgressEvent::Started {
345	                    event,
346	                    tool_name: tool_name.to_string(),
347	                    command: command.clone(),
348	                });
349	            }
350	
351	            match Self::run_command(
352	                command,
353	                event,
354	                tool_name,
355	                tool_input,
356	                tool_output,
357	                is_error,
358	                &payload,
359	                abort_signal,
360	            ) {
361	                HookCommandOutcome::Allow { parsed } => {
362	                    if let Some(reporter) = reporter.as_deref_mut() {
363	                        reporter.on_event(&HookProgressEvent::Completed {
364	                            event,
365	                            tool_name: tool_name.to_string(),
366	                            command: command.clone(),
367	                        });
368	                    }
369	                    merge_parsed_hook_output(&mut result, parsed);
370	                }
371	                HookCommandOutcome::Deny { parsed } => {
372	                    if let Some(reporter) = reporter.as_deref_mut() {
373	                        reporter.on_event(&HookProgressEvent::Completed {
374	                            event,
375	                            tool_name: tool_name.to_string(),
376	                            command: command.clone(),
377	                        });
378	                    }
379	                    merge_parsed_hook_output(&mut result, parsed);
380	                    result.denied = true;
381	                    return result;
382	                }
383	                HookCommandOutcome::Failed { parsed } => {
384	                    if let Some(reporter) = reporter.as_deref_mut() {
385	                        reporter.on_event(&HookProgressEvent::Completed {
386	                            event,
387	                            tool_name: tool_name.to_string(),
388	                            command: command.clone(),
389	                        });
390	                    }
391	                    merge_parsed_hook_output(&mut result, parsed);
392	                    result.failed = true;
393	                    return result;
394	                }
395	                HookCommandOutcome::Cancelled { message } => {
396	                    if let Some(reporter) = reporter.as_deref_mut() {
397	                        reporter.on_event(&HookProgressEvent::Cancelled {
398	                            event,
399	                            tool_name: tool_name.to_string(),
400	                            command: command.clone(),
401	                        });
402	                    }
403	                    result.cancelled = true;
404	                    result.messages.push(message);
405	                    return result;
406	                }
407	            }
408	        }
409	
410	        result
411	    }
