413	    #[allow(clippy::too_many_arguments)]
414	    fn run_command(
415	        command: &str,
416	        event: HookEvent,
417	        tool_name: &str,
418	        tool_input: &str,
419	        tool_output: Option<&str>,
420	        is_error: bool,
421	        payload: &str,
422	        abort_signal: Option<&HookAbortSignal>,
423	    ) -> HookCommandOutcome {
424	        let mut child = shell_command(command);
425	        child.stdin(Stdio::piped());
426	        child.stdout(Stdio::piped());
427	        child.stderr(Stdio::piped());
428	        child.env("HOOK_EVENT", event.as_str());
429	        child.env("HOOK_TOOL_NAME", tool_name);
430	        child.env("HOOK_TOOL_INPUT", tool_input);
431	        child.env("HOOK_TOOL_IS_ERROR", if is_error { "1" } else { "0" });
432	        if let Some(tool_output) = tool_output {
433	            child.env("HOOK_TOOL_OUTPUT", tool_output);
434	        }
435	
436	        match child.output_with_stdin(payload.as_bytes(), abort_signal) {
437	            Ok(CommandExecution::Finished(output)) => {
438	                let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
439	                let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
440	                let parsed = parse_hook_output(&stdout);
441	                let primary_message = parsed.primary_message().map(ToOwned::to_owned);
442	                match output.status.code() {
443	                    Some(0) => {
444	                        if parsed.deny {
445	                            HookCommandOutcome::Deny { parsed }
446	                        } else {
447	                            HookCommandOutcome::Allow { parsed }
448	                        }
449	                    }
450	                    Some(2) => HookCommandOutcome::Deny {
451	                        parsed: parsed.with_fallback_message(format!(
452	                            "{} hook denied tool `{tool_name}`",
453	                            event.as_str()
454	                        )),
455	                    },
456	                    Some(code) => HookCommandOutcome::Failed {
457	                        parsed: parsed.with_fallback_message(format_hook_failure(
458	                            command,
459	                            code,
460	                            primary_message.as_deref(),
461	                            stderr.as_str(),
462	                        )),
463	                    },
464	                    None => HookCommandOutcome::Failed {
465	                        parsed: parsed.with_fallback_message(format!(
466	                            "{} hook `{command}` terminated by signal while handling `{}`",
467	                            event.as_str(),
468	                            tool_name
469	                        )),
470	                    },
471	                }
472	            }
473	            Ok(CommandExecution::Cancelled) => HookCommandOutcome::Cancelled {
474	                message: format!(
475	                    "{} hook `{command}` cancelled while handling `{tool_name}`",
476	                    event.as_str()
477	                ),
478	            },
479	            Err(error) => HookCommandOutcome::Failed {
480	                parsed: ParsedHookOutput {
481	                    messages: vec![format!(
482	                        "{} hook `{command}` failed to start for `{}`: {error}",
483	                        event.as_str(),
484	                        tool_name
485	                    )],
486	                    ..ParsedHookOutput::default()
487	                },
488	            },
489	        }
490	    }
491	}
