522	fn merge_parsed_hook_output(target: &mut HookRunResult, parsed: ParsedHookOutput) {
523	    target.messages.extend(parsed.messages);
524	    if parsed.permission_override.is_some() {
525	        target.permission_override = parsed.permission_override;
526	    }
527	    if parsed.permission_reason.is_some() {
528	        target.permission_reason = parsed.permission_reason;
529	    }
530	    if parsed.updated_input.is_some() {
531	        target.updated_input = parsed.updated_input;
532	    }
