652	struct CommandWithStdin {
653	    command: Command,
654	}
655	
656	impl CommandWithStdin {
657	    fn new(command: Command) -> Self {
658	        Self { command }
659	    }
660	
661	    fn stdin(&mut self, cfg: Stdio) -> &mut Self {
662	        self.command.stdin(cfg);
663	        self
664	    }
665	
666	    fn stdout(&mut self, cfg: Stdio) -> &mut Self {
667	        self.command.stdout(cfg);
668	        self
669	    }
670	
671	    fn stderr(&mut self, cfg: Stdio) -> &mut Self {
672	        self.command.stderr(cfg);
673	        self
674	    }
