684	
685	    fn output_with_stdin(
686	        &mut self,
687	        stdin: &[u8],
688	        abort_signal: Option<&HookAbortSignal>,
689	    ) -> std::io::Result<CommandExecution> {
690	        let mut child = self.command.spawn()?;
691	        if let Some(mut child_stdin) = child.stdin.take() {
692	            child_stdin.write_all(stdin)?;
693	        }
694	
695	        loop {
696	            if abort_signal.is_some_and(HookAbortSignal::is_aborted) {
697	                let _ = child.kill();
698	                let _ = child.wait_with_output();
699	                return Ok(CommandExecution::Cancelled);
700	            }
701	
702	            match child.try_wait()? {
703	                Some(_) => return child.wait_with_output().map(CommandExecution::Finished),
704	                None => thread::sleep(Duration::from_millis(20)),
